{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction represents the classical Pinner reaction, showing the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and an alcohol (ethanol) under anhydrous acidic conditions (HCl). This is the quintessential first step of the Pinner synthesis, which is a gateway to esters or amidines. The reactants and product are simple, acyclic, and clearly illustrate the core transformation.",
    "collision_avoidance_note": "The use of simple, saturated aliphatic reactants (acetonitrile, ethanol) avoids overlap with reactions involving aromatic systems (e.g., Gattermann, Hoesch), complex rearrangements, or other functional groups. The product is the characteristic imino ether salt, which is specific to the Pinner reaction and distinct from amides (hydrolysis) or amines (reduction)."
  }
}
